// TRF_BuildItemsContext V3 - uses only $input, no cross-node paired item refs
const allItems = $input.all();
const firstItem = allItems[0]?.json || {};
const envelope = firstItem.envelope || {};
const router = firstItem.router || {};
const calendarEvents = firstItem._calendar_events || [];
const dbItems = allItems;
const TZ = 'America/Belem';
const now = new Date();
const nowLocal = now.toLocaleString('pt-BR', {timeZone: TZ});
const supabaseUrl = 'https://chtkfksjqcvlxpgyzlsf.supabase.co';
const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImNodGtma3NqcWN2bHhwZ3l6bHNmIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MjMwODU1NywiZXhwIjoyMDg3ODg0NTU3fQ.DM9wL7MlXRBuM_IYDk3pQ_q-WE7DYuwpqTTywg5A05U';
const ownerPhone = envelope.from_phone;
let masterPassword = null;
let userProvidedPassword = null;
try {
  const prefs = await this.helpers.httpRequest({method: 'GET', url: supabaseUrl + '/rest/v1/user_prefs?owner_phone=eq.' + encodeURIComponent(ownerPhone) + '&select=lead_time_scope', headers: {'apikey': supabaseKey, 'Authorization': 'Bearer ' + supabaseKey}, json: true});
  if (prefs && prefs.length > 0 && prefs[0].lead_time_scope) {
    const scope = prefs[0].lead_time_scope;
    if (scope.startsWith('master_pwd:')) masterPassword = scope.replace('master_pwd:', '');
  }
} catch(e) {}
const userMsg = (envelope.user_message || envelope.text_raw || '').toLowerCase();
if (masterPassword && userMsg.includes(masterPassword.toLowerCase())) userProvidedPassword = true;
let query_type = 'general';
let dateRangeLabel = '';
if (userMsg.match(/(?:^|\s)(hoje|agora|hj)(?:\s|$|[?,!.])/)) { query_type = 'today'; dateRangeLabel = 'hoje'; }
else if (userMsg.match(/amanh[aã]/)) { query_type = 'tomorrow'; dateRangeLabel = 'amanhã'; }
else if (userMsg.match(/(?:essa|esta)\s+semana/)) { query_type = 'this_week'; dateRangeLabel = 'esta semana'; }
else if (userMsg.match(/pr[oó]xim[oa]s?\s+dias?/) || userMsg.match(/pr[oó]xim[oa]s?\s+semana/)) { query_type = 'upcoming'; dateRangeLabel = 'próximos dias'; }
else if (userMsg.match(/(?:^|\s)(todos?|tudo|geral|completo)(?:\s|$|[?,!.])/)) { query_type = 'all'; dateRangeLabel = 'todos'; }
const sensitiveKeywords = ['senha', 'password', 'pin', 'código', 'codigo', 'segredo', 'secret', 'chave', 'token', 'acesso'];
function isSensitive(t, v) { return sensitiveKeywords.some(kw => ((t||'')+(v||'')).toLowerCase().includes(kw)); }
function maskContent(t) { if (!t) return t; if (t.length <= 2) return '***'; return t[0] + '*'.repeat(Math.min(t.length-2,8)) + t[t.length-1]; }
const reminders = [], notes = [], tasks = [];
const dbEventIds = new Set();
for (const item of dbItems) {
  const d = item.json || item;
  if (d._empty) continue;
  if (d.google_calendar_event_id) dbEventIds.add(d.google_calendar_event_id);
  const dueAt = d.event_datetime ? new Date(d.event_datetime).toLocaleString('pt-BR', {timeZone: TZ}) : null;
  const title = d.title || 'Sem título';
  const status = d.status || 'open';
  let details = d.value || '';
  const type = (d.type || 'note').toLowerCase();
  if (status === 'cancelled') continue;
  const sensitive = isSensitive(title, details);
  if (sensitive && masterPassword && !userProvidedPassword) details = details ? maskContent(details) : '';
  let statusLabel = '';
  if (d.event_datetime) {
    const dueDate = new Date(d.event_datetime);
    if (status === 'done') statusLabel = ' ✅ CONCLUÍDO';
    else if (dueDate < now) statusLabel = ' ⚠️ ATRASADO';
    else statusLabel = ' 🔵 PENDENTE';
  } else { statusLabel = status === 'done' ? ' ✅' : ''; }
  let line = '';
  if (type === 'note') {
    if (sensitive && masterPassword && !userProvidedPassword) line = '• ' + title + ' — 🔒 Conteúdo protegido' + statusLabel;
    else line = details ? '• ' + title + ' — Conteúdo: ' + details + statusLabel : '• ' + title + statusLabel;
  } else { line = '• ' + title + ' — ' + (dueAt || 'sem data') + statusLabel; }
  if (type === 'reminder') reminders.push(line);
  else if (type === 'task') tasks.push(line);
  else notes.push(line);
}
const calendarOnlyEvents = [];
for (const ev of calendarEvents) {
  if (!dbEventIds.has(ev.id)) {
    const startLocal = ev.start ? new Date(ev.start).toLocaleString('pt-BR', {timeZone: TZ}) : 'sem data';
    let line = '• ' + ev.title + ' — ' + startLocal + ' 🔵 PENDENTE';
    if (ev.meetLink) line += ' 📹 Meet';
    if (ev.attendees) line += ' 👥 ' + ev.attendees;
    line += ' [📅 Google Calendar]';
    calendarOnlyEvents.push(line);
  }
}
let items_context = '';
if (reminders.length > 0) items_context += 'LEMBRETES (' + reminders.length + '):\n' + reminders.join('\n') + '\n\n';
if (calendarOnlyEvents.length > 0) items_context += 'EVENTOS DO GOOGLE CALENDAR (' + calendarOnlyEvents.length + '):\n' + calendarOnlyEvents.join('\n') + '\n\n';
if (tasks.length > 0) items_context += 'TAREFAS (' + tasks.length + '):\n' + tasks.join('\n') + '\n\n';
if (notes.length > 0) items_context += 'NOTAS SALVAS (' + notes.length + '):\n' + notes.join('\n') + '\n\n';
if (!items_context) items_context = '(nenhum item encontrado para este usuário)';
const totalItems = reminders.length + tasks.length + notes.length + calendarOnlyEvents.length;
let passwordNotice = '';
if (masterPassword && !userProvidedPassword && notes.some(n => n.includes('🔒'))) passwordNotice = '\n⚠️ Notas protegidas. Informe sua contrasenha.';
return [{json: {envelope, router, items_context: items_context.trim() + passwordNotice, items_count: totalItems, reminders_count: reminders.length, notes_count: notes.length, tasks_count: tasks.length, calendar_events_count: calendarOnlyEvents.length, current_time: nowLocal, tz: TZ, query_type, date_range_label: dateRangeLabel, _password_protected: !!masterPassword, _password_provided: !!userProvidedPassword}}];

parameters.prompt:
Act as a strict JSON repair engine.

Main instruction:
Return ONLY one valid JSON object with exactly one key: "text" (string).
No extra text. No markdown. No code fences.

Example of the required output (literal):
{{"text":"your response here"}}

You will receive:
- error: {error}
- instructions: {instructions}
- completion: {completion}

Task:
Fix the completion so it becomes valid JSON matching the schema.
Return only the JSON.

