// TRF_FormatResponse V3 - Includes Google Calendar events + safe references
const firstItem = $input.all()[0]?.json || {};

// Get context - use .first() instead of .item to avoid paired item error
let context = {};
try { context = $('TRF_BuildItemsContext').first().json; } catch(e) { context = {}; }

let envelope = context.envelope || {};
if (!envelope.from_phone) {
  try { envelope = $('TRG_FromOrchestrator').first().json.envelope || {}; } catch(e) {}
}

// If empty
if (context._empty === true || !context.items_context) {
  return [{json: {
    envelope: envelope,
    user_message: envelope.user_message || '',
    agent_response: {items: [], agent: 'QUERY', items_count: 0},
    query_meta: {query_type: 'empty', tz: 'America/Belem', date_range_label: 'Nenhum item'}
  }}];
}

const TZ = context.tz || 'America/Belem';
const queryType = context.query_type || 'general';
const userMessage = envelope.user_message || context.user_message || '';

// Get current date info
const now = new Date();
const localNow = new Date(now.toLocaleString('en-US', {timeZone: TZ}));
const todayStr = localNow.toLocaleDateString('pt-BR', {timeZone: TZ});
const tomorrow = new Date(localNow);
tomorrow.setDate(tomorrow.getDate() + 1);
const tomorrowStr = tomorrow.toLocaleDateString('pt-BR', {timeZone: TZ});
const dayOfWeek = localNow.getDay();
const endOfWeek = new Date(localNow);
endOfWeek.setDate(endOfWeek.getDate() + (6 - dayOfWeek));
endOfWeek.setHours(23, 59, 59);
const weekdays = ['Domingo', 'Segunda', 'Terça', 'Quarta', 'Quinta', 'Sexta', 'Sábado'];

// Get DB items safely
let dbItems = [];
try { dbItems = $('GCal_MergeResults').all(); } catch(e) {
  try { dbItems = $('TRF_EnsureItems').all(); } catch(e2) { dbItems = []; }
}

// Get calendar events from context
const calendarEvents = [];
try {
  const mergeFirst = $('GCal_MergeResults').first().json;
  const cals = mergeFirst._calendar_events || [];
  calendarEvents.push(...cals);
} catch(e) {}

// Build DB items with date info
const allItems = [];
const dbEventIds = new Set();

for (const item of dbItems) {
  const d = item.json || item;
  if (d._empty) continue;
  if (d.google_calendar_event_id) dbEventIds.add(d.google_calendar_event_id);

  let dateStr = '', weekday = '', timeStr = '', itemDate = null;
  if (d.event_datetime) {
    const dt = new Date(d.event_datetime);
    itemDate = new Date(dt.toLocaleString('en-US', {timeZone: TZ}));
    dateStr = dt.toLocaleDateString('pt-BR', {timeZone: TZ});
    timeStr = dt.toLocaleTimeString('pt-BR', {timeZone: TZ, hour: '2-digit', minute: '2-digit', hour12: false});
    weekday = weekdays[new Date(dt.toLocaleString('en-US', {timeZone: TZ})).getDay()];
  }

  let status = 'pending';
  if (d.status === 'done') status = 'done';
  else if (d.status === 'notified') status = 'notified';

  const itemObj = {date: dateStr, weekday, time: timeStr, title: d.title || 'Sem título', status, type: (d.type || 'note').toLowerCase(), value: d.value || '', source: 'supabase'};

  let include = false;
  switch (queryType) {
    case 'today': include = (dateStr === todayStr); break;
    case 'tomorrow': include = (dateStr === tomorrowStr); break;
    case 'this_week':
      if (itemDate) include = (itemDate >= new Date(localNow.getFullYear(), localNow.getMonth(), localNow.getDate()) && itemDate <= endOfWeek);
      if (!d.event_datetime && (d.type === 'task' || d.type === 'note')) include = true;
      break;
    case 'upcoming':
      if (itemDate) include = (itemDate >= new Date(localNow.getFullYear(), localNow.getMonth(), localNow.getDate()));
      if (!d.event_datetime && (d.type === 'task' || d.type === 'note')) include = true;
      break;
    default: include = true;
  }
  if (include) allItems.push(itemObj);
}

// Add Google Calendar events NOT in DB
for (const ev of calendarEvents) {
  if (dbEventIds.has(ev.id)) continue;

  let dateStr = '', weekday = '', timeStr = '', itemDate = null;
  if (ev.start) {
    const dt = new Date(ev.start);
    itemDate = new Date(dt.toLocaleString('en-US', {timeZone: TZ}));
    dateStr = dt.toLocaleDateString('pt-BR', {timeZone: TZ});
    timeStr = dt.toLocaleTimeString('pt-BR', {timeZone: TZ, hour: '2-digit', minute: '2-digit', hour12: false});
    weekday = weekdays[new Date(dt.toLocaleString('en-US', {timeZone: TZ})).getDay()];
  }

  const itemObj = {date: dateStr, weekday, time: timeStr, title: ev.title || 'Sem título', status: 'pending', type: 'event', value: '', source: 'google_calendar', meetLink: ev.meetLink || '', attendees: ev.attendees || ''};

  let include = false;
  switch (queryType) {
    case 'today': include = (dateStr === todayStr); break;
    case 'tomorrow': include = (dateStr === tomorrowStr); break;
    case 'this_week':
      if (itemDate) include = (itemDate >= new Date(localNow.getFullYear(), localNow.getMonth(), localNow.getDate()) && itemDate <= endOfWeek);
      break;
    case 'upcoming':
      if (itemDate) include = (itemDate >= new Date(localNow.getFullYear(), localNow.getMonth(), localNow.getDate()));
      break;
    default: include = true;
  }
  if (include) allItems.push(itemObj);
}

// Sort by date/time
allItems.sort((a, b) => {
  if (!a.date && !b.date) return 0;
  if (!a.date) return 1;
  if (!b.date) return -1;
  const dateA = a.date.split('/').reverse().join('-') + 'T' + (a.time || '00:00');
  const dateB = b.date.split('/').reverse().join('-') + 'T' + (b.time || '00:00');
  return dateA.localeCompare(dateB);
});

return [{json: {
  envelope: envelope,
  user_message: userMessage,
  agent_response: {items: allItems, agent: 'QUERY', items_count: allItems.length},
  query_meta: {query_type: queryType, tz: TZ, current_time: context.current_time, date_range_label: context.date_range_label || ''}
}}];

// TRF_EnsureItems: Garante que SEMPRE há output mesmo com banco vazio
// E SEMPRE propaga o envelope do trigger
const items = $input.all();

// Pegar envelope do trigger (SEMPRE disponível)
let envelope = {};
try { envelope = $('TRG_FromOrchestrator').item.json.envelope || {}; } catch(e) {}
if (!envelope.from_phone) {
  // Fallback: tentar do primeiro item
  envelope = items[0]?.json?.envelope || {};
}

if (items.length === 0 || (items.length === 1 && Object.keys(items[0].json).length <= 1)) {
  // Banco vazio — retornar item sintético COM envelope
  return [{
    json: {
      _empty: true,
      _message: 'Nenhum item encontrado no banco',
      envelope: envelope
    }
  }];
}

// Items existem — passar adiante com envelope garantido
return items.map(item => ({
  json: {
    ...item.json,
    _empty: false,
    envelope: envelope
  }
}));

// GCal_PrepareDates: Calculate date range for Google Calendar query
const items = $input.all();
const envelope = $('TRG_FromOrchestrator').first().json.envelope || {};
const router = $('TRG_FromOrchestrator').first().json.router || {};
const userMsg = (envelope.user_message || envelope.text_raw || '').toLowerCase();
const TZ = 'America/Belem';
const dbItems = items.map(i => i.json);
const now = new Date();
const todayStart = new Date(now.toLocaleString('en-US', {timeZone: TZ}));
todayStart.setHours(0, 0, 0, 0);
let timeMin, timeMax;
const dateMatch = userMsg.match(/dia\s+(\d{1,2})(?:\s+e\s+(\d{1,2}))?\s+de\s+(\w+)/);
if (dateMatch) {
  const months = {'janeiro': 0, 'fevereiro': 1, 'março': 2, 'marco': 2, 'abril': 3, 'maio': 4, 'junho': 5, 'julho': 6, 'agosto': 7, 'setembro': 8, 'outubro': 9, 'novembro': 10, 'dezembro': 11};
  const day1 = parseInt(dateMatch[1]);
  const day2 = dateMatch[2] ? parseInt(dateMatch[2]) : day1;
  const month = months[dateMatch[3]] !== undefined ? months[dateMatch[3]] : now.getMonth();
  timeMin = new Date(now.getFullYear(), month, day1, 0, 0, 0);
  timeMax = new Date(now.getFullYear(), month, day2, 23, 59, 59);
} else if (userMsg.match(/amanh[aã]/)) {
  timeMin = new Date(todayStart.getTime() + 86400000);
  timeMax = new Date(todayStart.getTime() + 172800000);
} else if (userMsg.match(/hoje/)) {
  timeMin = todayStart;
  timeMax = new Date(todayStart.getTime() + 86400000);
} else if (userMsg.match(/(?:essa|esta)\s+semana/) || userMsg.match(/semana/)) {
  timeMin = todayStart;
  timeMax = new Date(todayStart.getTime() + 604800000);
} else if (userMsg.match(/pr[oó]xim/)) {
  timeMin = todayStart;
  timeMax = new Date(todayStart.getTime() + 1209600000);
} else {
  timeMin = todayStart;
  timeMax = new Date(todayStart.getTime() + 604800000);
}
return [{json: {_db_items: dbItems, _timeMin: timeMin.toISOString(), _timeMax: timeMax.toISOString(), envelope: envelope, router: router}}];

// GCal_MergeResults: Merge DB items + Google Calendar events
const calendarRawEvents = $input.all();
const prepData = $('GCal_PrepareDates').first().json;
const dbItems = prepData._db_items || [];
const envelope = prepData.envelope || {};
const router = prepData.router || {};
const calendarEvents = calendarRawEvents
  .filter(e => e.json && e.json.id)
  .map(e => {
    const ev = e.json;
    return {
      id: ev.id || '',
      title: ev.summary || 'Sem título',
      start: ev.start?.dateTime || ev.start?.date || ev.start || '',
      end: ev.end?.dateTime || ev.end?.date || ev.end || '',
      description: ev.description || '',
      meetLink: ev.hangoutLink || '',
      attendees: (ev.attendees || []).map(a => a.email || a).join(', '),
      source: 'google_calendar'
    };
  });
if (dbItems.length === 0) {
  return [{json: {_empty: true, _message: 'Nenhum item no banco', envelope: envelope, router: router, _calendar_events: calendarEvents, _calendar_events_count: calendarEvents.length}}];
}
return dbItems.map((item, idx) => ({json: {...item, envelope: envelope, router: router, _calendar_events: idx === 0 ? calendarEvents : [], _calendar_events_count: idx === 0 ? calendarEvents.length : 0}}));
